New-Item -ItemType Directory -Force -Path "$base\backend\src" | Out-Null
[System.IO.File]::WriteAllBytes("$base\backend\src\db.js", [System.Convert]::FromBase64String(""))

New-Item -ItemType Directory -Force -Path "$base\backend\src\routes" | Out-Null
